import React from "react"
import PropTypes from "prop-types"
import { ExpressionTreeEditor } from "react-expression-tree"

function InnerExpressionTreeViewer({ nodes, edges, height }) {
  return (
    <div style={{marginBottom: '1em'}}>
      <ExpressionTreeEditor 
        width={600}
        height={height}
        fontSize={24}
        fullDisabled={true}
        connectorPlaceholder="{{}}"
        initialState={{
          initialNodes: nodes,
          initialEdges: edges
        }}
      />
    </div>
  );
}

InnerExpressionTreeViewer.propTypes = {
  nodes: PropTypes.array.isRequired,
  edges: PropTypes.array.isRequired,
  height: PropTypes.number
}

InnerExpressionTreeViewer.defaultProps = {
  height: 300
}

export default InnerExpressionTreeViewer;
